const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');
const jwt = require('jsonwebtoken');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

const PORT = process.env.PORT || 3000;
const JWT_SECRET = process.env.JWT_SECRET || 'change-me-in-production';
const SESSION_TTL_MS = 1000 * 60 * 60 * 24 * 7;

const playersBySocket = new Map();
const sessions = new Map();

function safeString(v, maxLen = 32) {
  if (typeof v !== 'string') return null;
  const s = v.trim();
  if (!s || s.length > maxLen) return null;
  return s;
}

function safeScore(v) {
  const n = Number(v);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.floor(n);
}

function createSession(username) {
  const sessionId = crypto.randomUUID();
  const token = jwt.sign({ sid: sessionId, username }, JWT_SECRET, { expiresIn: '7d' });
  sessions.set(sessionId, {
    username,
    createdAt: Date.now(),
    expiresAt: Date.now() + SESSION_TTL_MS
  });
  return { sessionId, token };
}

function verifyToken(token) {
  try {
    const payload = jwt.verify(token, JWT_SECRET);
    const record = sessions.get(payload.sid);
    if (!record) return null;
    if (record.expiresAt < Date.now()) {
      sessions.delete(payload.sid);
      return null;
    }
    return { sessionId: payload.sid, username: record.username };
  } catch {
    return null;
  }
}

function authenticateSocket(socket, auth) {
  const username = safeString(auth?.username, 24);
  const score = safeScore(auth?.score);
  const token = typeof auth?.token === 'string' ? auth.token : null;

  if (token) {
    const verified = verifyToken(token);
    if (!verified) return { ok: false, error: 'Invalid session token' };
    return { ok: true, username: verified.username, score: score ?? 0, token };
  }

  if (!username) return { ok: false, error: 'Username required' };

  const session = createSession(username);
  return { ok: true, username, score: score ?? 0, token: session.token };
}

function leaderboardSnapshot() {
  return [...playersBySocket.values()]
    .map(p => ({ username: p.username, score: p.score }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 100);
}

app.get('/health', (_req, res) => {
  res.json({ ok: true });
});

app.get('/leaderboard', (_req, res) => {
  res.json({ leaderboard: leaderboardSnapshot() });
});

io.use((socket, next) => {
  const result = authenticateSocket(socket, socket.handshake.auth || {});
  if (!result.ok) return next(new Error(result.error));
  socket.data.username = result.username;
  socket.data.score = result.score;
  socket.data.token = result.token;
  next();
});

io.on('connection', socket => {
  const player = {
    socketId: socket.id,
    username: socket.data.username,
    score: socket.data.score,
    connectedAt: Date.now()
  };

  playersBySocket.set(socket.id, player);

  socket.emit('session', {
    username: player.username,
    score: player.score,
    token: socket.data.token
  });

  io.emit('leaderboard', leaderboardSnapshot());

  socket.on('move', payload => {
    const move = payload && typeof payload === 'object' ? payload : {};
    const validated = {
      x: Number(move.x),
      y: Number(move.y)
    };

    if (!Number.isFinite(validated.x) || !Number.isFinite(validated.y)) {
      socket.emit('error', { message: 'Invalid move' });
      return;
    }

    socket.emit('moveAccepted', {
      x: validated.x,
      y: validated.y
    });
  });

  socket.on('score', payload => {
    const nextScore = safeScore(payload?.score);
    if (nextScore === null) {
      socket.emit('error', { message: 'Invalid score' });
      return;
    }

    const playerData = playersBySocket.get(socket.id);
    if (!playerData) return;

    playerData.score = nextScore;
    playersBySocket.set(socket.id, playerData);

    io.emit('leaderboard', leaderboardSnapshot());
  });

  socket.on('disconnect', () => {
    playersBySocket.delete(socket.id);
    io.emit('leaderboard', leaderboardSnapshot());
  });
});

setInterval(() => {
  const now = Date.now();
  for (const [sid, session] of sessions.entries()) {
    if (session.expiresAt < now) sessions.delete(sid);
  }
}, 60 * 1000).unref();

